+/**
+ * Get a code fence that doesn't conflict with content.
+ * Uses longer fences (````, `````, etc.) if content contains backticks.
+ */
+function getCodeFence(content: string): string {
+  let fence = "```";
+  while (content.includes(fence)) {
+    fence += "`";
+  }
+  return fence;
+}
